+import { describe, expect, it, vi } from "vitest";
+import { createFetch } from "../src/index.ts";
+
+const circuitBreaker = {
+  threshold: 2,
+  cooldown: 100,
+  failureStatusCodes: [503],
+};
+
+function response(status = 200, body = "ok") {
+  return new Response(body, { status, headers: { "content-type": "text/plain" } });
+}
+
+describe("circuit breaker", () => {
+  it("opens per origin and shares state with derived clients", async () => {
+    const fetch = vi.fn(async () => response(503));
+    const client = createFetch({ fetch });
+    const child = client.create({});
+
+    await expect(client("https://one.test/a", { circuitBreaker, retry: false })).rejects.toThrow();
+    await expect(child(new URL("https://one.test/b"), { circuitBreaker, retry: false })).rejects.toThrow();
+    await expect(client(new Request("https://one.test/c"), { circuitBreaker })).rejects.toThrow(
+      "Circuit breaker is open"
+    );
+    await expect(client("https://two.test/a", { circuitBreaker, retry: false })).rejects.toThrow();
+    expect(fetch).toHaveBeenCalledTimes(3);
+  });
+
+  it("uses the rewritten effective origin and does not count retries repeatedly", async () => {
+    const fetch = vi.fn(async () => response(503));
+    const client = createFetch({ fetch });
+
+    await expect(
+      client("/a", {
+        baseURL: "https://original.test",
+        circuitBreaker: { ...circuitBreaker, threshold: 1 },
+        retry: 1,
+        onRequest(context) {
+          context.request = "https://rewritten.test/a";
+        },
+      })
+    ).rejects.toThrow();
+    await expect(
+      client("https://rewritten.test/b", { circuitBreaker, retry: false })
+    ).rejects.toThrow("Circuit breaker is open");
+    expect(fetch).toHaveBeenCalledTimes(2);
+  });
+
+  it("limits half-open probes and closes after a successful probe", async () => {
